import os
from google.cloud import storage

def get_latest_model(bucket_name, model_path):
    """
    Get the name of the latest version of a model in a Cloud Storage bucket.
    :param bucket_name: The name of the GCS bucket containing the models.
    :return: The name of the latest model.
    """
    client = storage.Client()
    bucket = client.get_bucket(bucket_name)
    blobs = list(bucket.list_blobs(prefix=model_path))
    
    if not blobs:
        raise FileNotFoundError(f"No models found in {bucket_name} under path {model_path}")
        
    sorted_blobs = sorted(blobs, key=lambda x: int(x.name.split("_")[-1]))
    return os.path.join(model_path, sorted_blobs[-1].name)

def download_model(bucket_name, model_path, local_path):
    """
    Download a single model from Cloud Storage.
    :param bucket_name: The name of the GCS bucket containing the models.
    :param model_path: The path to the model in Cloud Storage.
    :return: None
    """
    client = storage.Client()
    blob = client.get_blob(bucket_name, model_path)
    
    blob.download_to_filename(local_path)

if __name__ == "__main__":
    # Read the environment variable for model path
    MODEL_PATH = os.environ.get('MODEL_PATH')
    if not MODEL_PATH:
        print("Environment variable 'MODEL_PATH' must be set")
        exit(1)

    # Fetch latest model from cloud storage
    bucket_name, model_path = MODEL_PATH.split('/')
    local_path = f'/tmp/model/{model_path}'
    
    try:
        model_path = get_latest_model(bucket_name, model_path)
        download_model(bucket_name, model_path, local_path)
    except Exception as e:
        print(f"Failed to load latest model: {e}")
        exit(1)

    # Load ML model from local path
    import tensorflow as tf
    tf.keras.models.load_model(local_path)